  "version": "1.0.0",
  "description": "Executor inteligente para o Lançamento Automático do IdentificaPix.",
  "permissions": [
    "storage",
    "activeTab",
    "scripting",
    "tabs"
  ],
  "host_permissions": [
    "<all_urls>"
  ],
