chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {
  console.log("[IdentificaPix Ext] Message received in background:", msg);

  if (msg.type === "EXECUTE_ITEM" && sender.tab) {
    // Relay command to the content script of the same tab
    chrome.tabs.sendMessage(sender.tab.id, msg);
  }

  if (msg.type === "LEARN_SELECTOR") {
    // Logic to store or pass back to the app for training
    console.debug("[IdentificaPix Ext] Selector learned:", msg.payload);
  }

  sendResponse({ status: "ok" });
  return true;
});

// Bridge: WebApp -> Extension
window.addEventListener("message", (event) => {
  if (!event.data || event.data.source !== "IdentificaPixIA") return;

  const { type, payload } = event.data.payload;

  if (type === "START_OBSERVING") {
    window.__IDENTIFICAPIX_OBSERVING__ = true;
    console.log("%c[IdentificaPix] Modo observação ativado.", "color: #10b981; font-weight: bold;");
  } else if (type === "STOP_OBSERVING") {
    window.__IDENTIFICAPIX_OBSERVING__ = false;
    console.log("%c[IdentificaPix] Modo observação desativado.", "color: #ef4444; font-weight: bold;");
  }

  chrome.runtime.sendMessage({
    type: "FROM_IDENTIFICAPIX",
    payload: event.data.payload
  });
});

// Helper: Generates unique CSS selector
function generateSelector(el) {
  if (el.id) return "#" + el.id;
  if (el.name) return `[name="${el.name}"]`;
  const tag = el.tagName.toLowerCase();
  if (el.className && typeof el.className === "string") {
    const classes = el.className.trim().split(/\s+/).join('.');
    return `${tag}.${classes}`;
  }
  return tag;
}

// Interaction Observer (Learning Mode)
const captureInteraction = (e) => {
  if (!window.__IDENTIFICAPIX_OBSERVING__) return;

  const selector = generateSelector(e.target);
  const action = e.type === 'click' ? 'click' : 'input';

  chrome.runtime.sendMessage({
    type: "LEARN_SELECTOR",
    payload: {
      action,
      selector,
      timestamp: new Date().toISOString()
    }
  });
};

window.addEventListener("click", captureInteraction, true);
window.addEventListener("input", captureInteraction, true);

// Execution Listener (Automation Mode)
chrome.runtime.onMessage.addListener((msg) => {
  if (msg.type === "EXECUTE_ITEM") {
    console.log("%c[IdentificaPix IA] Executando tarefa automatizada...", "color: #3b82f6; font-weight: bold;");

    const { action, selector, payload } = msg.payload;
    const target = document.querySelector(selector || 'input, [role="button"], button');

    if (!target) {
      console.warn("[IdentificaPix IA] Alvo não localizado:", selector);
      return;
    }

    target.style.outline = "4px solid #f59e0b";
    target.scrollIntoView({ behavior: 'smooth', block: 'center' });

    setTimeout(() => {
      if (action === 'click') {
        target.click();
      } else {
        const val = payload?.amount || payload?.value || "";
        target.value = val;
        target.dispatchEvent(new Event('input', { bubbles: true }));
        target.dispatchEvent(new Event('change', { bubbles: true }));
      }
      target.style.outline = "";
    }, 800);
  }
});
